// // This module decrements a 4-bit counter from 15 to 0 on each positive edge of the clock, resetting to 15 when it reaches 0.
module counter (
    input clk,
    input reset,
    output reg [3:0] out
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            out <= 4'b0000;
        end else begin
            if (out == 4'b1111) begin
                out <= 4'b0000;
            end else begin
                out <= out + 1;
            end
        end
    end

endmodule
